-- Migração Jobs (SonicJS -> EdgePress)
-- Post type: jobs + taxonomia type=categorias (PT/EN)
-- 209 trabalhos, 9 categorias, 252 vínculos. Pré-requisito: seed (attachment, locales pt_BR/en_US)
-- meta posttype "jobs" mantido para compatibilidade farramedia (GetContent)
-- Custom fields (ficha técnica, vídeos, etc.): migrate-jobs-custom-fields.sql

-- Post type Jobs
INSERT OR IGNORE INTO post_types (slug, name, meta_schema, created_at, updated_at)
SELECT 'jobs', 'Jobs', '[{"key":"menu_order","type":"number","default":0},{"key":"parent_id","type":"number"},{"key":"show_in_menu","type":"boolean","default":false},{"key":"menu_options","type":"array","default":["list","new","taxonomies_type_categorias"]},{"key":"icon","type":"string","default":"line-md:briefcase"},{"key":"post_thumbnail","type":"boolean","default":true},{"key":"taxonomy","type":"array","default":["categorias"]},{"key":"post_types","type":"array","default":["custom_fields"]}]', 0, 0
WHERE NOT EXISTS (SELECT 1 FROM post_types WHERE slug='jobs');

-- Garante post_types custom_fields no schema jobs (idempotente)
UPDATE post_types SET meta_schema = '[{"key":"menu_order","type":"number","default":0},{"key":"parent_id","type":"number"},{"key":"show_in_menu","type":"boolean","default":false},{"key":"menu_options","type":"array","default":["list","new","taxonomies_type_categorias"]},{"key":"icon","type":"string","default":"line-md:briefcase"},{"key":"post_thumbnail","type":"boolean","default":true},{"key":"taxonomy","type":"array","default":["categorias"]},{"key":"post_types","type":"array","default":["custom_fields"]}]', updated_at = 0
WHERE slug='jobs';

-- Menu admin Jobs
INSERT OR IGNORE INTO posts (post_type_id, title, slug, status, meta_values, created_at, updated_at)
SELECT (SELECT id FROM post_types WHERE slug='jobs' LIMIT 1), 'jobs', 'menu-jobs', 'published', '{"show_in_menu":true,"menu_options":["list","new","taxonomies_type_categorias"],"menu_order":9,"icon":"line-md:briefcase","post_types":["custom_fields"]}', 0, 0
WHERE NOT EXISTS (SELECT 1 FROM posts WHERE slug='menu-jobs');

-- Traduções admin: postType.jobs + menu.option.taxonomies_type_categorias
INSERT INTO translations (namespace, key, created_at, updated_at) SELECT 'postType', 'jobs', 0, 0 WHERE NOT EXISTS (SELECT 1 FROM translations WHERE namespace='postType' AND key='jobs');
INSERT INTO translations (namespace, key, created_at, updated_at) SELECT 'menu.option', 'taxonomies_type_categorias', 0, 0 WHERE NOT EXISTS (SELECT 1 FROM translations WHERE namespace='menu.option' AND key='taxonomies_type_categorias');
INSERT OR REPLACE INTO translations_languages (id_translations, id_locale_code, value) SELECT (SELECT id FROM translations WHERE namespace='postType' AND key='jobs' LIMIT 1), (SELECT id FROM locales WHERE locale_code='en_US' LIMIT 1), 'Jobs';
INSERT OR REPLACE INTO translations_languages (id_translations, id_locale_code, value) SELECT (SELECT id FROM translations WHERE namespace='postType' AND key='jobs' LIMIT 1), (SELECT id FROM locales WHERE locale_code='es_ES' LIMIT 1), 'Trabajos';
INSERT OR REPLACE INTO translations_languages (id_translations, id_locale_code, value) SELECT (SELECT id FROM translations WHERE namespace='postType' AND key='jobs' LIMIT 1), (SELECT id FROM locales WHERE locale_code='pt_BR' LIMIT 1), 'Trabalhos';
INSERT OR REPLACE INTO translations_languages (id_translations, id_locale_code, value) SELECT (SELECT id FROM translations WHERE namespace='menu.option' AND key='taxonomies_type_categorias' LIMIT 1), (SELECT id FROM locales WHERE locale_code='en_US' LIMIT 1), 'Categories';
INSERT OR REPLACE INTO translations_languages (id_translations, id_locale_code, value) SELECT (SELECT id FROM translations WHERE namespace='menu.option' AND key='taxonomies_type_categorias' LIMIT 1), (SELECT id FROM locales WHERE locale_code='es_ES' LIMIT 1), 'Categorías';
INSERT OR REPLACE INTO translations_languages (id_translations, id_locale_code, value) SELECT (SELECT id FROM translations WHERE namespace='menu.option' AND key='taxonomies_type_categorias' LIMIT 1), (SELECT id FROM locales WHERE locale_code='pt_BR' LIMIT 1), 'Categorias';

-- Raiz taxonomia categorias (jobs)
INSERT OR IGNORE INTO taxonomies (name, slug, type, parent_id, created_at, updated_at)
SELECT 'Categorias', 'categorias', 'categorias', NULL, 0, 0
WHERE NOT EXISTS (SELECT 1 FROM taxonomies WHERE slug='categorias' AND type='categorias');

