INSERT OR IGNORE INTO posts (post_type_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at)
SELECT (SELECT id FROM post_types WHERE slug='jobs' LIMIT 1), (SELECT id FROM locales WHERE locale_code='en_US' LIMIT 1), 'Corrida de São Sylvester | Paramount+', 'corrida-de-sao-sylvester-paramount-en-us', '', 'Paramount+ approached the entertainment agency Farra to create promotional material for the new series "Tulsa King". We created the São Sylvester Race, an official street race in honor of the great star Sylvester Stallone, the star of the series. The intention was to unite all the fame of Sylvester Stallone''s iconic characters and introduce his new character in Tulsa King, "Dwight Manfredi". The race was free and took place at the São Paulo Botanical Garden. Fans were encouraged to dress up as their favorite Stallone characters. At the event, many activations connected with the Tulsa King series, and all the set design, country band and stages of the event referred to the universe of the series. We created a registration website, produced more than 10 advertising films, including announcements, stories, pre-, during and post-event promos and hero film, in addition to the entire production of the race.', 'published', '{"order":119,"image":"https://bucket.farra.media/corrida.png","language":"enUS","slug":"corrida-de-sao-sylvester-paramount","videos":["https://vimeo.com/1010371240","https://vimeo.com/1010371031","https://vimeo.com/1010370651"],"videosHome":["https://vimeo.com/1010371240"],"videosHomeOrder":null,"fichaTecnica":[{"title":"Agency and Production:","content":"Farra"},{"title":"Creation and Writing:","content":"Gui Cintra, Andr\u00e9 Brandt, Maria Clara Lucci, Sergio Barbosa, Rodrigo Moura"},{"title":"Direction:","content":"Gui Cintra"},{"title":"Executive Production:","content":"Gui Vieira e Tayna Adam"},{"title":"Production Direction:","content":"Juliana Hodas"},{"title":"Steering Assistance:","content":"Sophia Cordazzo"},{"title":"Production:","content":"Jo\u00e3o Pedro Mello"},{"title":"Executive Production Assistance:","content":"Beatriz Fontana"},{"title":"Art Production:","content":"Jenny Shauff"},{"title":"Costume:","content":"Fabiana Souza"},{"title":"Make: ","content":"Dani Gonc"},{"title":"Cinematography:","content":"Heitor Cavalheiro"},{"title":"Post-production Coordination:","content":"Fred Kesselring"},{"title":"Edition:","content":"Mike Prado"},{"title":"Color Correction:","content":"Hugo Moura"},{"title":"Art Direction:","content":"Gustavo Moura"},{"title":"Motion Design:","content":"Alex Kundera "},{"title":"Design:","content":"Bia Vidal"},{"title":"Audio:","content":"Gui Picolo - Dream Box"},{"title":"Financial Coordination:","content":"Andressa Carrijo"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"150f88d8-0aab-4c39-a3c8-f0f21bdb5103","legacy_posttype":"jobs"}', 1726763360000, 1726763360000, 1767787931732
