SELECT (SELECT id FROM post_types WHERE slug='jobs' LIMIT 1), (SELECT id FROM locales WHERE locale_code='pt_BR' LIMIT 1), 'Corrida de São Sylvester | Paramount+', 'corrida-de-sao-sylvester-paramount-pt-br', '', 'A Paramount+ buscou a agência de entretenimento Farra para criar peças para divulgação da nova série "Tulsa King", criamos assim a: Corrida de São Sylvester, uma corrida de rua oficial em homenagem ao grande astro Sylvester Stallone protagonista da série. A intenção foi unir toda fama dos personagens icônicos do Sylvester Stallone e apresentar seu novo personagem em Tulsa King "Dwight Manfredi". A corrida foi gratuita e aconteceu no Jardim Botânico de São Paulo, os fãs foram estimulados a irem fantasiados dos seus personagens favoritos do Stallone, no evento, muitas ativações conectavam com os núcleos da série Tulsa King, e todo cenografia, banda country e palcos do evento remetiam ao universo da série. Criamos site de inscrições, produção de mais de 10 filmes publicitários, entre chamadas, stories, promo pré, durante e pós evento e filme hero, além claro de toda a produção da corrida.', 'published', '{"order":118,"image":"https://bucket.farra.media/corrida.png","language":"ptbr","slug":"corrida-de-sao-sylvester-paramount","videos":["https://vimeo.com/1010371240","https://vimeo.com/1010371031","https://vimeo.com/1010370651"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Ag\u00eancia e Produ\u00e7\u00e3o","content":"Farra"},{"title":"Cria\u00e7\u00e3o e Reda\u00e7\u00e3o:","content":"Gui Cintra, Andr\u00e9 Brandt, Maria Clara Lucci, Sergio Barbosa, Rodrigo Moura"},{"title":"Dire\u00e7\u00e3o","content":"Gui Cintra"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira e Tayna Adam"},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o:","content":"Juliana Hodas"},{"title":"Assist\u00eancia de Dire\u00e7\u00e3o:","content":"Sophia Cordazzo"},{"title":"Produ\u00e7\u00e3o:","content":"Jo\u00e3o Pedro Mello"},{"title":"Assist\u00eancia de Produ\u00e7\u00e3o Executiva:","content":"Beatriz Fontana"},{"title":"Produ\u00e7\u00e3o de Arte:","content":"Jenny Shauff"},{"title":"Figurino:","content":"Fabiana Souza"},{"title":"Make: ","content":"Dani Gonc"},{"title":"Dire\u00e7\u00e3o de Fotografia:","content":"Heitor Cavalheiro"},{"title":"Coordena\u00e7\u00e3o de P\u00f3s-produ\u00e7\u00e3o:","content":"Fred Kesselring"},{"title":"Edi\u00e7\u00e3o:","content":"Mike Prado"},{"title":"Corre\u00e7\u00e3o de Cor:","content":"Hugo Moura"},{"title":"Dire\u00e7\u00e3o de Arte:","content":"Gustavo Moura"},{"title":"Motion Design:","content":"Alex Kundera "},{"title":"Design:","content":"Bia Vidal"},{"title":"\u00c1udio:","content":"Gui Picolo - Dream Box"},{"title":"Coordena\u00e7\u00e3o Financeira:","content":"Andressa Carrijo"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"f476b2d2-7936-45a7-a1ff-1591f015619e","legacy_posttype":"jobs"}', 1726762026000, 1726762026000, 1767788371649
