SELECT (SELECT id FROM post_types WHERE slug='jobs' LIMIT 1), (SELECT id FROM locales WHERE locale_code='en_US' LIMIT 1), 'Gastronomia Periférica | Continental', 'gastronomia-periferica-continental-en-us', '', 'The Peripheral Gastronomy project, created by Edson Leite and Adélia Rodrigues, has always enchanted Farra precisely because of its premise: talking and teaching about gastronomy to an audience that needs quality information and training.

Transforming the knowledge spread by the GP people into content for the internet (increasing the project’s reach even more) was necessary, and identifying the lack of this type of content on the internet was fundamental to start building the GP channel on YouTube, back in 2018 .

It took 2 years to present the project, knocking from door to door, looking for partners to get this idea off the ground. Until we found at Continental Eletrodomésticos and SOKO the perfect sponsors to make it happen.

A project made by the periphery and for the periphery, which puts Farra face to face with other players in the digital market, always with excellence in production and purpose!', 'published', '{"order":107,"image":"https://bucket.farra.media/gp.png","language":"enUS","slug":"gastronomia-periferica-continental","videos":["https://vimeo.com/720732573","https://vimeo.com/720738724","https://vimeo.com/720743549","https://vimeo.com/720746990","https://vimeo.com/720754306","https://vimeo.com/733744331\""],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Executive Production","content":"Gui Vieira"},{"title":"Project Management","content":"Yasmin Persi"},{"title":"Production Coordinator","content":"Tarcila Vila"},{"title":"Writing","content":"Sergio Barbosa e L\u00e9o Parron"},{"title":"Production and creation","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"7fa3c1f4-15b3-4238-a7d7-62be004367cf","legacy_posttype":"jobs"}', 1719709013000, 1719709013000, 1727792297896
