SELECT (SELECT id FROM post_types WHERE slug='jobs' LIMIT 1), (SELECT id FROM locales WHERE locale_code='pt_BR' LIMIT 1), 'Gastronomia Periférica | Continental', 'gastronomia-periferica-continental-pt-br', '', 'O projeto Gastronomia Periférica, criado por Edson Leite e Adélia Rodrigues, sempre encantou a Farra justamente por sua premissa: falar e ensinar sobre gastronomia para um público que precisa de informação e formação de qualidade.Transformar o conhecimento espalhado pela galera da GP em conteúdo para internet (aumentando ainda mais o alcance do projeto) era algo necessário, e identificar a falta desse tipo de conteúdo na internet foi fundamental para começar a construção do canal GP no YouTube, lá em 2018.  Foram 2 anos apresentando o projeto, batendo de porta em porta, na busca de parceiros para tirar essa ideia do papel. Até que encontramos na Continental Eletrodomésticos e na SOKO os padrinhos perfeitos para fazer acontecer. Um projeto feito pela periferia e para a periferia, que coloca a Farra frente a frente a outros players do mercado digital, sempre com excelência em produção e propósito!', 'published', '{"order":107,"image":"https://bucket.farra.media/gp.png","language":"ptbr","slug":"gastronomia-periferica-continental","videos":["https://vimeo.com/720732573","https://vimeo.com/720737430","https://vimeo.com/720742041","https://vimeo.com/720745540","https://vimeo.com/720754306","https://vimeo.com/720765824","https://vimeo.com/733744331"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira"},{"title":"Gerente de Projetos","content":"Yasmin Persi"},{"title":"Coordena\u00e7\u00e3o de Produ\u00e7\u00e3o","content":"Tarcila Vila"},{"title":"Roteiro","content":"Sergio Barbosa e L\u00e9o Parron"},{"title":"Produ\u00e7\u00e3o e Cria\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"06d474c0-842c-4e68-9980-6cace48fd908","legacy_posttype":"jobs"}', 17